def test_standard_schedule_recurring_transfer_one_above_cap_2501_returns_422(standard_auth_token, api_base_url, next_monday):
    payload = {
        "amount": 2501,
        "currency": "USD",
        "frequency": "WEEKLY",
        "start_date": next_monday,
        "destination_account": "<dest_account_id>"
    }
    resp = <http_client>.post(
        f"{api_base_url}/transfers/recurring",
        json=payload,
        headers={"Authorization": f"Bearer {standard_auth_token}"}
    )
    assert resp.status_code == 422, f"Expected 422 at boundary+1, got {resp.status_code}: {resp.text}"
    body = resp.json()
    assert "error" in body

def test_tier_cap_decision_table_standard_vs_premium_same_amount(standard_auth_token, premium_auth_token, api_base_url, next_monday):
    payload = {
        "amount": 5000,
        "currency": "USD",
        "frequency": "WEEKLY",
        "start_date": next_monday,
        "destination_account": "<dest_account_id>"
    }
    std_resp = <http_client>.post(
        f"{api_base_url}/transfers/recurring",
        json=payload,
        headers={"Authorization": f"Bearer {standard_auth_token}"}
    )
    assert std_resp.status_code == 422, f"Standard: expected 422, got {std_resp.status_code}"

    prem_resp = <http_client>.post(
        f"{api_base_url}/transfers/recurring",
        json=payload,
        headers={"Authorization": f"Bearer {premium_auth_token}"}
    )
    assert prem_resp.status_code == 201, f"Premium: expected 201, got {prem_resp.status_code}"
    body = prem_resp.json()
    assert "schedule_id" in body
    assert "next_run" in body
